#include <iostream>
#include <stdexcept>

int main() {
 try {
 int age = -5;
 if (age < 0) {
 throw std::invalid_argument("Age cannot be negative");
 }
 }
 catch (const std::invalid_argument& e) {
 std::cout << "Invalid argument: " << e.what() << std::endl;
 }
 catch (const std::exception& e) {
 std::cout << "Exception: " << e.what() << std::endl;
 }
 return 0;
}

#include <iostream>
#include <stdexcept>

void func() {
 try {
 throw 20; // throws int
 }
 catch (int e) {
 std::cout << "Caught in func: " << e << std::endl;
 throw; // rethrow the same exception
 }
}

int main() {
 try {
 func();
 }
 catch (int e) {
 std::cout << "Caught in main: " << e << std::endl;
 }
 catch (...) {
 std::cout << "Caught unknown exception" << std::endl;
 }
 return 0;
}

#include <iostream>
#include <exception>
#include <string>

class MyException : public std::exception {
private:
 std::string msg;
public:
 MyException(const std::string& m) : msg(m) {}
 const char* what() const noexcept override {
 return msg.c_str();
 }
};

void divide(int a, int b) {
 if (b == 0) {
 throw MyException("Division by zero not allowed");
 }
 std::cout << a << " / " << b << " = " << a/b << std::endl;
}

int main() {
 try {
 divide(10, 0);
 }
 catch (const std::exception& e) {
 std::cout << "Exception: " << e.what() << std::endl;
 }
 return 0;
}

#include <iostream>
#include <stdexcept>

class Resource {
public:
 Resource(int val) : value(val) {
 if (val < 0) throw std::runtime_error("Invalid resource value");
 std::cout << "Resource created: " << value << std::endl;
 }
 ~Resource() { std::cout << "Resource destroyed" << std::endl; }
 int value;
};

class MyClass {
 Resource* res;
public:
 MyClass(int v) try : res(new Resource(v)) {
 std::cout << "MyClass constructed" << std::endl;
 }
 catch (const std::exception& e) {
 std::cout << "Constructor failed: " << e.what() << std::endl;
 throw; // Re-throw to indicate construction failure
 }
 ~MyClass() { delete res; std::cout << "MyClass destroyed" << std::endl; }
};

int main() {
 try {
 MyClass obj(-5);
 }
 catch (...) {
 std::cout << "Exception caught in main" << std::endl;
 }
 return 0;
}

#include <iostream>
#include <exception>

void safeFunction() noexcept {
 std::cout << "This function won't throw" << std::endl;
}

int division(int a, int b) noexcept(false) {
 if (b == 0) throw std::runtime_error("Division by zero");
 return a / b;
}

int main() {
 try {
 safeFunction(); // Can throw but won't
 int result = division(10, 0);
 }
 catch (const std::exception& e) {
 std::cout << "Exception: " << e.what() << std::endl;
 }
 return 0;
}
